  phrases: [{ ar: "هل التصوير مسموح؟", en: "Are photos allowed?", ipa: "hal at-tas-weer mas-mooh" }, { ar: "أين المدخل؟", en: "Where is the entrance?", ipa: "ayn al-mad-khal" }, { ar: "أين أضع الحذاء؟", en: "Where do I put the shoes?", ipa: "ayn a-da al-hi-dhaa" }, { ar: "أريد لباسا مناسبا", en: "I want appropriate clothing", ipa: "u-reed li-baa-san mu-naa-si-ban" }, { ar: "سأكون هادئا", en: "I will be quiet", ipa: "sa-a-koon haa-di-an" }, { ar: "أحترم القواعد", en: "I respect the rules", ipa: "ah-ta-rim al-qa-waa-id" }],
  grammar: "سـ before a verb means “will.” سأكون means “I will be.” This helps you make polite future statements, like سأكون هادئا, “I will be quiet.”",
  practice: ["Ask if photos are allowed.", "Ask where to put your shoes.", "Say you respect the rules.", "Practice saying “I will be quiet.”", "Imagine visiting a mosque and ask two respectful questions."]
