  phrases: [{ ar: "أين خدمة الغسيل؟", en: "Where is the laundry service?", ipa: "ayn khid-mat al-gha-seel" }, { ar: "هذه الملابس متسخة", en: "These clothes are dirty", ipa: "haa-dhi-hi al-ma-laa-bis mut-sa-kha" }, { ar: "أريد ملابس نظيفة", en: "I want clean clothes", ipa: "u-reed ma-laa-bis na-dhee-fa" }, { ar: "هل يكون جاهزا غدا؟", en: "Will it be ready tomorrow?", ipa: "hal ya-koon jaa-hi-zan gha-dan" }, { ar: "أحتاج إلى صابون", en: "I need soap", ipa: "ah-taaj i-la saa-boon" }, { ar: "هل عندكم خدمة إصلاح؟", en: "Do you have repair service?", ipa: "hal in-da-kum khid-mat is-laah" }],
