  phrases: [{ ar: "لا أفهم العربية جيدا", en: "I do not understand Arabic well", ipa: "laa af-ham al-a-ra-bee-ya jay-yi-dan" }, { ar: "هل تتكلم الإنجليزية؟", en: "Do you speak English?", ipa: "hal ta-ta-kal-lam al-in-glee-zee-ya" }, { ar: "كرر، من فضلك", en: "Repeat, please", ipa: "kar-rir min fad-lik" }, { ar: "ببطء، من فضلك", en: "Slowly, please", ipa: "bi-but min fad-lik" }, { ar: "ما معنى هذه الكلمة؟", en: "What does this word mean?", ipa: "maa ma-na haa-dhi-hi al-ka-li-ma" }, { ar: "الآن واضح", en: "Now it is clear", ipa: "al-aan waa-dih" }],
  grammar: "جيدا means “well.” لا أفهم العربية جيدا means “I do not understand Arabic well.” This phrase is honest and helpful because many people will slow down or switch languages.",
  practice: ["Say you do not understand Arabic well.", "Ask someone to repeat.", "Ask someone to speak slowly.", "Ask if they speak English.", "Ask what a word means."]
