var CONVERSATIONS_EN_AR = [
{ title: "Ordering coffee at a café", scene: "You are at a café in Riyadh in the morning. The server greets you and you order coffee without sugar, plus cold water.", lines: [{ who: "them", ar: "مرحبا، ماذا تريد؟", en: "Hello, what would you like?" }, { who: "you", ar: "أريد قهوة، من فضلك", en: "I want coffee, please." }, { who: "them", ar: "هل تريد السكر؟", en: "Do you want sugar?" }, { who: "you", ar: "لا، بدون سكر", en: "No, without sugar." }, { who: "them", ar: "هل تريد حليبا؟", en: "Do you want milk?" }, { who: "you", ar: "نعم، قليلا من الحليب", en: "Yes, a little milk." }, { who: "them", ar: "هل تريد شيئا آخر؟", en: "Do you want anything else?" }, { who: "you", ar: "ماء بارد، من فضلك", en: "Cold water, please." }, { who: "them", ar: "بالطبع، تفضل", en: "Of course, here you are." }, { who: "you", ar: "شكرا، القهوة ممتازة", en: "Thank you, the coffee is excellent." }, { who: "them", ar: "عفوا، أهلا وسهلا", en: "You’re welcome, welcome." }] },
{ title: "Checking into a hotel", scene: "You arrive at a hotel in Muscat after a long trip. The receptionist asks for your reservation and passport.", lines: [{ who: "them", ar: "مساء الخير، أهلا بك في الفندق", en: "Good evening, welcome to the hotel." }, { who: "you", ar: "مساء الخير، عندي حجز", en: "Good evening, I have a reservation." }, { who: "them", ar: "ما اسمك؟", en: "What is your name?" }, { who: "you", ar: "اسمي جيمس كانون", en: "My name is James Cannon." }, { who: "them", ar: "جواز السفر، من فضلك", en: "Passport, please." }, { who: "you", ar: "تفضل، هذا جواز السفر", en: "Here you are, this is the passport." }, { who: "them", ar: "الحجز لليلتين، صحيح؟", en: "The reservation is for two nights, correct?" }, { who: "you", ar: "نعم، ليلتان", en: "Yes, two nights." }, { who: "them", ar: "هذا مفتاح الغرفة", en: "This is the room key." }, { who: "you", ar: "شكرا، أين المصعد؟", en: "Thank you, where is the elevator?" }, { who: "them", ar: "المصعد على اليمين", en: "The elevator is on the right." }, { who: "you", ar: "شكرا جزيلا", en: "Thank you very much." }] },
{ title: "Asking for directions to the metro", scene: "You are walking in Cairo and need to find the metro station. You stop a local person politely and ask for directions.", lines: [{ who: "you", ar: "لو سمحت، ممكن سؤال؟", en: "Excuse me, may I ask a question?" }, { who: "them", ar: "نعم، تفضل", en: "Yes, go ahead." }, { who: "you", ar: "أين محطة المترو؟", en: "Where is the metro station?" }, { who: "them", ar: "امشِ مستقيما ثم اذهب يسارا", en: "Walk straight, then go left." }, { who: "you", ar: "هل هي قريبة؟", en: "Is it near?" }, { who: "them", ar: "نعم، قريبة جدا", en: "Yes, very near." }, { who: "you", ar: "كم دقيقة؟", en: "How many minutes?" }, { who: "them", ar: "خمس دقائق فقط", en: "Only five minutes." }, { who: "you", ar: "هل الخروج هناك؟", en: "Is the exit there?" }, { who: "them", ar: "نعم، هناك على اليمين", en: "Yes, there on the right." }, { who: "you", ar: "شكرا على المساعدة", en: "Thank you for the help." }, { who: "them", ar: "عفوا، رحلة سعيدة", en: "You’re welcome, have a good trip." }] },
{ title: "Eating at a restaurant", scene: "You are at a restaurant in Beirut for dinner. You ask about spicy food, order chicken with rice, and request the bill.", lines: [{ who: "them", ar: "أهلا وسهلا، هل تريد القائمة؟", en: "Welcome, do you want the menu?" }, { who: "you", ar: "نعم، أريد القائمة، من فضلك", en: "Yes, I want the menu, please." }, { who: "them", ar: "تفضل، هذا طبق اليوم", en: "Here you are, this is today’s dish." }, { who: "you", ar: "هل هذا حار؟", en: "Is this spicy?" }, { who: "them", ar: "قليلا، ليس حارا جدا", en: "A little, not very spicy." }, { who: "you", ar: "أريد دجاجا مع أرز", en: "I want chicken with rice." }, { who: "them", ar: "هل تريد سلطة أيضا؟", en: "Do you want salad also?" }, { who: "you", ar: "نعم، سلطة وماء", en: "Yes, salad and water." }, { who: "them", ar: "بالطبع، هل تريد شيئا آخر؟", en: "Of course, do you want anything else?" }, { who: "you", ar: "لا، شكرا", en: "No, thank you." }, { who: "you", ar: "الفاتورة، من فضلك", en: "The bill, please." }, { who: "them", ar: "حالا، تفضل", en: "Right away, here you are." }] },
{ title: "Buying a transit ticket", scene: "You are at a metro station in Dubai. You need one ticket and want to know which line goes downtown.", lines: [{ who: "them", ar: "صباح الخير، كيف أساعدك؟", en: "Good morning, how can I help you?" }, { who: "you", ar: "أريد تذكرة واحدة، من فضلك", en: "I want one ticket, please." }, { who: "them", ar: "إلى أين؟", en: "To where?" }, { who: "you", ar: "إلى وسط المدينة", en: "To downtown." }, { who: "them", ar: "خذ الخط الأحمر", en: "Take the red line." }, { who: "you", ar: "أي رصيف؟", en: "Which platform?" }, { who: "them", ar: "الرصيف الثاني", en: "Platform two." }, { who: "you", ar: "كم السعر؟", en: "How much is the price?" }, { who: "them", ar: "خمسة دراهم", en: "Five dirhams." }, { who: "you", ar: "هل أستطيع الدفع بالبطاقة؟", en: "Can I pay by card?" }, { who: "them", ar: "نعم، البطاقة مقبولة", en: "Yes, card is accepted." }, { who: "you", ar: "شكرا، أين الخروج إلى الرصيف؟", en: "Thank you, where is the exit to the platform?" }] },
{ title: "Shopping in a market", scene: "You are in a market in Fez looking for a small blue gift. You ask about price, color, and paying cash.", lines: [{ who: "them", ar: "أهلا، تفضل", en: "Hello, come in." }, { who: "you", ar: "أريد هدية صغيرة", en: "I want a small gift." }, { who: "them", ar: "عندي هذا الصندوق الجميل", en: "I have this beautiful box." }, { who: "you", ar: "هل عندك لون أزرق؟", en: "Do you have a blue color?" }, { who: "them", ar: "نعم، هذا أزرق", en: "Yes, this is blue." }, { who: "you", ar: "كم هذا؟", en: "How much is this?" }, { who: "them", ar: "خمسون درهما", en: "Fifty dirhams." }, { who: "you", ar: "هذا غال قليلا", en: "This is a little expensive." }, { who: "them", ar: "أربعون درهما", en: "Forty dirhams." }, { who: "you", ar: "جيد، هل أستطيع الدفع نقدا؟", en: "Good, can I pay cash?" }, { who: "them", ar: "نعم، بالطبع", en: "Yes, of course." }, { who: "you", ar: "شكرا، أحب هذا اللون", en: "Thank you, I like this color." }] },
{ title: "At the pharmacy", scene: "You are in Kuwait City and have a headache. You go to a pharmacy to ask for medicine and whether you need a prescription.", lines: [{ who: "them", ar: "مرحبا، كيف أساعدك؟", en: "Hello, how can I help you?" }, { who: "you", ar: "عندي ألم في الرأس", en: "I have a headache." }, { who: "them", ar: "هل عندك حمّى؟", en: "Do you have a fever?" }, { who: "you", ar: "لا، فقط ألم في الرأس", en: "No, only a headache." }, { who: "them", ar: "هل عندك حساسية؟", en: "Do you have an allergy?" }, { who: "you", ar: "نعم، عندي حساسية من المكسرات", en: "Yes, I have a nut allergy." }, { who: "them", ar: "حسنا، هذا دواء مناسب", en: "Okay, this medicine is suitable." }, { who: "you", ar: "هل أحتاج إلى وصفة؟", en: "Do I need a prescription?" }, { who: "them", ar: "لا، لا تحتاج إلى وصفة", en: "No, you do not need a prescription." }, { who: "you", ar: "كم الجرعة؟", en: "What is the dose?" }, { who: "them", ar: "قرص واحد مع الماء", en: "One tablet with water." }, { who: "you", ar: "شكرا جزيلا", en: "Thank you very much." }] },
{ title: "Small talk with a local", scene: "You are sitting near the corniche in Doha and start a friendly conversation with a local person. You ask for a recommendation and talk about the city.", lines: [{ who: "you", ar: "مرحبا، هذه المدينة جميلة", en: "Hello, this city is beautiful." }, { who: "them", ar: "أهلا، نعم، الدوحة جميلة جدا", en: "Hi, yes, Doha is very beautiful." }, { who: "you", ar: "أنا جديد هنا", en: "I am new here." }, { who: "them", ar: "أهلا وسهلا، من أين أنت؟", en: "Welcome, where are you from?" }, { who: "you", ar: "أنا من أمريكا", en: "I am from America." }, { who: "them", ar: "هل هذه أول زيارة لك؟", en: "Is this your first visit?" }, { who: "you", ar: "نعم، هذه أول زيارة لي", en: "Yes, this is my first visit." }, { who: "them", ar: "هل تحب الطعام هنا؟", en: "Do you like the food here?" }, { who: "you", ar: "نعم، الطعام رائع", en: "Yes, the food is wonderful." }, { who: "you", ar: "هل عندك توصية لمطعم؟", en: "Do you have a restaurant recommendation?" }, { who: "them", ar: "نعم، يوجد مطعم جيد قرب البحر", en: "Yes, there is a good restaurant near the sea." }, { who: "you", ar: "شكرا، سررت بالحديث معك", en: "Thank you, I enjoyed talking with you." }] }
];
